targets.expr:
(
  0 * (
    sum by(shard) (
      gitlab_component_shard_ops:rate_5m{component="api_requests", shard=~".+-(${stack:pipe})", shard=~"$shard"}
    ) > 0
  )
)
or
(
  0 * sum by(shard) (gitlab_runner_version_info{shard=~".+-(${stack:pipe})", shard=~"$shard"}) + 1
  unless on(shard) (
    sum by(shard) (
      gitlab_component_shard_ops:rate_5m{component="api_requests", shard=~".+-(${stack:pipe})", shard=~"$shard"}
    ) > 0
  )
)
or
(
  0 * sum by(shard) (last_over_time(gitlab_runner_version_info{shard=~".+-(${stack:pipe})", shard=~"$shard"}[24h])) + 2
  unless on(shard) (
    sum by(shard) (gitlab_runner_version_info{shard=~".+-(${stack:pipe})", shard=~"$shard"})
  )
)

sum by(status, shard, endpoint) (
  increase(
    gitlab_runner_api_request_statuses_total{shard=~".+-(${stack:pipe})", shard=~"$shard"} [$__rate_interval]
  )
)

sum by (executor_stage, stage, shard) (
  gitlab_runner_jobs{state="running", shard=~".+-(${stack:pipe})", shard=~"$shard"}
)

(
  sum by (shard) (
    gitlab_runner_jobs{job="hosted-runners-prometheus-agent", shard=~".+-(${stack:pipe})", shard=~"$shard"}
  )
  /
  (
    sum by (shard) (
      gitlab_runner_concurrent{job="hosted-runners-prometheus-agent", shard=~".+-(${stack:pipe})", shard=~"$shard"}
    ) > 0
  )
)
or
(
  0 * sum by (shard) (
    gitlab_runner_version_info{shard=~".+-(${stack:pipe})", shard=~"$shard"}
  )
)

(
  sum by (shard) (
    gitlab_runner_jobs{job="hosted-runners-prometheus-agent", shard=~".+-(${stack:pipe})", shard=~"$shard"}
  )
  /
  (
    sum by (shard) (
      gitlab_runner_limit{job="hosted-runners-prometheus-agent", shard=~".+-(${stack:pipe})", shard=~"$shard"}
    ) > 0
  )
)
or
(
  0 * sum by (shard) (
    gitlab_runner_version_info{shard=~".+-(${stack:pipe})", shard=~"$shard"}
  )
)

sum by (shard) (
  rate(gitlab_runner_job_queue_duration_seconds_sum{shard=~".+-(${stack:pipe})", shard=~"$shard"}[5m])
)
/
sum by (shard) (
  gitlab_component_shard_ops:rate_5m{component="pending_builds", shard=~".+-(${stack:pipe})", shard=~"$shard"}
)

sum by (shard) (
  rate(
    gitlab_runner_acceptable_job_queuing_duration_exceeded_total{shard=~".+-(${stack:pipe})", shard=~"$shard"}[$__rate_interval]
  )
)
/
sum by (shard) (
  rate(
    gitlab_runner_jobs_total{shard=~".+-(${stack:pipe})", shard=~"$shard"}[$__rate_interval]
  )
)

sum by(shard) (
  fleeting_provisioner_instances{state=~"running|creating|deleting", shard=~".+-(${stack:pipe})", shard=~"$shard"}
)
/
sum by(shard) (
  fleeting_provisioner_max_instances{shard=~".+-(${stack:pipe})", shard=~"$shard"}
)

sum by(shard) (
  fleeting_taskscaler_tasks{shard=~".+-(${stack:pipe})", shard=~"$shard", state!~"idle|reserved"}
)
/
sum by(shard) (
  fleeting_provisioner_max_instances{shard=~".+-(${stack:pipe})", shard=~"$shard"}
  *
  fleeting_taskscaler_max_tasks_per_instance{shard=~".+-(${stack:pipe})", shard=~"$shard"}
)

sum by(status) (
  increase(
    gitlab_runner_api_request_statuses_total{shard=~".+-(${stack:pipe})", shard=~"$shard", endpoint="request_job", status=~".*"}[$__rate_interval]
  )
)

sum by(status) (
  increase(
    gitlab_runner_api_request_statuses_total{shard=~".+-(${stack:pipe})", shard=~"$shard", endpoint="patch_trace", status=~".*"}[$__rate_interval]
  )
)

sum by(status) (
  increase(
    gitlab_runner_api_request_statuses_total{shard=~".+-(${stack:pipe})", shard=~"$shard", endpoint="update_job", status=~".*"}[$__rate_interval]
  )
)
